local ESPGroup = Tabs.Misc:AddRightGroupbox("ESP ")
ESPGroup:AddToggle("ESPEnabled",{
    Text="Aktifkan ESP Hewan Peliharaan ",Default=false,
    Callback=function(v)
        M.ESPState.Enabled=v
        if v then
            Library:Notify({Title="ESP ",Description="ESP hewan peliharaan diaktifkan. ",Time=2})
            task.spawn(function()
                while M.ESPState.Enabled do
                    M.updateESP()
                    task.wait(2)
                end
                M.clearESP()
            end)
        else
            M.clearESP()
        end
    end,
})
ESPGroup:AddLabel("Warna sesuai tingkat kelangkaan. ")

task.spawn(function()
    while true do
        local pets, islandName = M.getNearestIslandPets()
        M.AutoCatchState.CurrentIsland = islandName
        local count = 0
        for _ in pairs(M.AutoCatchState.CaughtPets) do count+=1 end
        local cur    = M.getCurrentWeather()
        local isAct  = cur~="Default" and cur~=""
        local bosses = M.getAllBossesOnMap()
        islandLabel:SetText( "Island: "         ..islandName.." ")
        caughtLabel:SetText( "Session Caught: " ..count.." ")
        nearbyLabel:SetText( "Nearby Pets: "    ..#pets.." ")
        bossMapLabel:SetText("Bosses: "         ..#bosses.." ")
        weatherLabel:SetText("Weather: "        ..cur.." ")
        eventLabel:SetText(  "Active Event: "   ..(isAct and cur or "None").." ")
        bossLabel:SetText(   "Boss: "           ..M.AutoCatchState.BossStatus.." ")
        task.wait(0.5)
    end
end)

